import { DebuggerMesssge } from '../../collect/hooktype';


export default class Et {
  collect: any
  url: string
  apply(collect: any, config: any) {
    if (!config.event_verify_url) return
    if (typeof config.event_verify_url !== 'string') {
      console.log('please use correct et_test url')
      return
    }
    this.collect = collect;
    this.url = `${config.event_verify_url}/v1/list_test`
    collect.on(collect.Types.SubmitBefore, (data) => {
      this.verify(data)
    });
    collect.on(collect.Types.AbVerify, (data) => {
      this.verify(data)
    })
  }
  verify(data) {
    this.collect.requestManager.useBeacon({
      url: this.url,
      data
    })
    this.collect.emit(DebuggerMesssge.DEBUGGER_MESSAGE, { type: DebuggerMesssge.DEBUGGER_MESSAGE_EVENT, info: 'SDK Report ByteIo Verify Request', time: Date.now(), data: data, code: 200, status: 'success', verifyType: true })
  }
}